package genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.service.VehicleAssignmentService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/assignments") public class VehicleAssignmentController { private final VehicleAssignmentService service; public VehicleAssignmentController(VehicleAssignmentService service){this.service=service;} @GetMapping public List<VehicleAssignmentResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleAssignmentResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleAssignmentResponse create(@RequestBody VehicleAssignmentUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleAssignmentResponse update(@PathVariable UUID id,@RequestBody VehicleAssignmentUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
